--
-- Table structure for table `asset_transfer`
--

DROP TABLE IF EXISTS `asset_transfer`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `asset_transfer` (
  `transfer_id` int NOT NULL AUTO_INCREMENT,
  `asset_no` varchar(20) NOT NULL,
  `asset_class` varchar(50) DEFAULT NULL,
  `item_name` varchar(200) DEFAULT NULL,
  `transfer_date` date DEFAULT NULL,
  `before_dept` varchar(100) DEFAULT NULL,
  `before_location` varchar(200) DEFAULT NULL,
  `before_detail` varchar(200) DEFAULT NULL,
  `after_dept` varchar(100) DEFAULT NULL,
  `after_location` varchar(200) DEFAULT NULL,
  `after_detail` varchar(200) DEFAULT NULL,
  `remark` text,
  `reg_date` datetime DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`transfer_id`),
  KEY `idx_transfer_asset` (`asset_no`),
  KEY `idx_transfer_date` (`transfer_date`),
  CONSTRAINT `asset_transfer_ibfk_1` FOREIGN KEY (`asset_no`) REFERENCES `assets` (`asset_no`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=141 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

