DROP TABLE IF EXISTS `assets`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `assets` (
  `asset_no` varchar(20) NOT NULL,
  `acq_type` varchar(50) DEFAULT NULL,
  `asset_class` varchar(50) DEFAULT NULL,
  `category_large` varchar(50) DEFAULT NULL,
  `category_mid` varchar(50) DEFAULT NULL,
  `category_small` varchar(50) DEFAULT NULL,
  `item_name` varchar(200) DEFAULT NULL,
  `spec` varchar(500) DEFAULT NULL,
  `manufacturer` varchar(100) DEFAULT NULL,
  `model` varchar(200) DEFAULT NULL,
  `acq_date` date DEFAULT NULL,
  `acq_price` decimal(15,0) DEFAULT NULL,
  `residual_value` decimal(15,0) DEFAULT NULL,
  `useful_life` int DEFAULT NULL,
  `quantity` int DEFAULT '1',
  `location` varchar(200) DEFAULT NULL,
  `detail_location` varchar(200) DEFAULT NULL,
  `latitude` decimal(10,7) DEFAULT NULL,
  `longitude` decimal(10,7) DEFAULT NULL,
  `floor` int DEFAULT NULL,
  `room_no` varchar(50) DEFAULT NULL,
  `manage_dept` varchar(100) DEFAULT NULL,
  `manager_name` varchar(50) DEFAULT NULL,
  `manager_id` varchar(50) DEFAULT NULL,
  `use_dept` varchar(100) DEFAULT NULL,
  `asset_status` varchar(50) DEFAULT '사용중',
  `detail_status` varchar(50) DEFAULT NULL,
  `inspect_date` date DEFAULT NULL,
  `remark` text,
  `reg_date` datetime DEFAULT CURRENT_TIMESTAMP,
  `mod_date` datetime DEFAULT CURRENT_TIMESTAMP,
  `room_id` int DEFAULT NULL,
  PRIMARY KEY (`asset_no`),
  KEY `idx_assets_class` (`asset_class`),
  KEY `idx_assets_location` (`location`),
  KEY `idx_assets_dept` (`manage_dept`),
  KEY `idx_assets_status` (`asset_status`),
  KEY `idx_assets_item` (`item_name`)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
